#include<bits/stdc++.h>
#define rep(a,b,c) for(register int c=(a);c<=(b);++c)
const int INF = 0x3f3f3f3f;
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
int dp[1048576],a[11][11],b[11][11],n,m,len; bool vis[1048576];
inline void print2(int p){if(p>1)print2(p>>1);putchar((p&1)+'0');}
inline int dfs(int cur,bool typ)
{
	if(vis[cur])return dp[cur];
	dp[cur]=typ?INF:-INF; int l=0,r=m+1;
	rep(0,n+m-1,i)
	{
		(cur&(1<<i))?l++:r--;if(!l||r==m+1)continue;
		if(!(cur&(1<<i-1))&&(cur&(1<<i)))
		{
			int x=cur^(3<<(i-1));
			dp[cur]=typ?
			min(dp[cur],dfs(x,typ^1)-b[l][r]):
			max(dp[cur],dfs(x,typ^1)+a[l][r]);
		}
	}
	vis[cur]=1;return dp[cur];
}
int main()
{
	n=read(); m=read(); len=(1<<n)-1;
	rep(1,n,i)rep(1,m,j)a[i][j]=read();
	rep(1,n,i)rep(1,m,j)b[i][j]=read();
	dp[len]=0;vis[len]=1;printf("%d",dfs(len<<m,0));
}
